using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap the JSONPlaceholder REST API using constructor-injected HttpClient.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions s_jsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Retrieve a post by its ID from the REST API.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post to retrieve (1-100).")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {PostId}", postId);
        var json = await httpClient.GetStringAsync($"posts/{postId}", cancellationToken);
        return json;
    }

    [McpServerTool, Description("List all posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Optional user ID to filter posts by author.")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"posts?userId={userId}" : "posts";
        logger.LogInformation("Listing posts: {Url}", url);

        var json = await httpClient.GetStringAsync(url, cancellationToken);

        // Re-serialize to return concise summaries
        var posts = JsonSerializer.Deserialize<JsonElement>(json);
        return JsonSerializer.Serialize(posts, s_jsonOptions);
    }

    [McpServerTool, Description("List comments on a specific post.")]
    public async Task<string> GetComments(
        [Description("The post ID to retrieve comments for.")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching comments for post {PostId}", postId);
        var json = await httpClient.GetStringAsync($"posts/{postId}/comments", cancellationToken);
        return json;
    }

    [McpServerTool(ReadOnly = false, Destructive = false),
     Description("Create a new post with the given title, body, and user ID.")]
    public async Task<string> CreatePost(
        [Description("Title of the new post.")] string title,
        [Description("Body content of the new post.")] string body,
        [Description("User ID of the post author.")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating post for user {UserId}", userId);

        var payload = new { title, body, userId };
        var response = await httpClient.PostAsJsonAsync("posts", payload, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }
}

